class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7
        dp = [[[0, 0] for _ in range(limit + 1)] for _ in range(zero + 1)]
        dp[1][1][0] = 1
        dp[1][1][1] = 1
        for z in range(zero + 1):
            for o in range(one + 1):
                for last in range(2):
                    if z > 0:
                        if last == 0:
                            dp[z][o][0] = (dp[z][o][0] + dp[z - 1][o][1]) % MOD
                        elif o >= limit and z >= limit:
                            continue
                        else:
                            dp[z][o][0] = (dp[z][o][0] + dp[z - 1][o][last]) % MOD
                    if o > 0:
                        if last == 1:
                            dp[z][o][1] = (dp[z][o][1] + dp[z][o - 1][0]) % MOD
                        elif o >= limit and z >= limit:
                            continue
                        else:
                            dp[z][o][1] = (dp[z][o][1] + dp[z][o - 1][last]) % MOD
        return (dp[zero][one][0] + dp[zero][one][1]) % MOD
